queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?screenwriters a :Screenwriters .
    ?screenwriters p:name ?name .
    ?screenwriters p:Number_Of_Projects_Completed ?number_of_projects_completed_f .
    FILTER((STR(?number_of_projects_completed_f) = "15" || STR(?number_of_projects_completed_f) = "15.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?editors a :Editors .
    ?editors p:name ?name .
    ?editors p:Number_Of_Projects_Completed ?number_of_projects_completed_f .
    FILTER((STR(?number_of_projects_completed_f) = "15" || STR(?number_of_projects_completed_f) = "15.0"))
    BIND(?name AS ?o0)
  }
}

